import pytest

from worker import MAX_RETRIES, process


def test_success_first_try():
    assert process(2, lambda job: job * 10) == 20


def test_retries_then_succeeds():
    calls = []

    def flaky(job):
        calls.append(job)
        if len(calls) < 3:
            raise ValueError("transient")
        return "ok"

    assert process("j", flaky) == "ok"
    assert len(calls) == MAX_RETRIES


def test_gives_up_after_max_retries():
    def always_fails(job):
        raise ValueError("boom")

    with pytest.raises(RuntimeError):
        process("j", always_fails)

MAX_RETRIES = 3


def process(job, handler):
    """Run handler(job), retrying up to MAX_RETRIES times on failure."""
    last_error = None
    for _ in range(MAX_RETRIES):
        try:
            return handler(job)
        except Exception as exc:  # noqa: BLE001 - workers must survive any handler error
            last_error = exc
    raise RuntimeError(f"job failed after {MAX_RETRIES} attempts") from last_error

